import "core-js/modules/es.json.stringify.js";
import { ref, onMounted } from 'vue';
import NavbarSection from '@/components/NavbarSection.vue';
import FooterSection from '@/components/FooterSection.vue';
export default {
  __name: 'LogoDesignPage',
  setup(__props, {
    expose: __expose
  }) {
    __expose();
    const quoteForm = ref({
      full_name: '',
      email: '',
      phone: '',
      company: '',
      notes: ''
    });
    const openFaqIndex = ref(null);
    const showScrollTop = ref(false);
    const isSubmitting = ref(false);
    const faqs = ref([{
      question: "What logo design services do you offer?",
      answer: "We offer complete logo design services including custom logo creation, brand identity packages, logo revisions, vector files delivery (AI, EPS, SVG, PNG, PDF), and brand guideline documents."
    }, {
      question: "How affordable are your graphic design services?",
      answer: "Our pricing is very competitive and flexible. We have packages starting from basic logo design to premium brand identity kits. Quality design should be accessible to businesses of all sizes."
    }]);

    // Functions
    const toggleFAQ = index => {
      openFaqIndex.value = openFaqIndex.value === index ? null : index;
    };
    const handleQuoteSubmit = async () => {
      isSubmitting.value = true;
      try {
        const response = await fetch('https://jaexlfmjjzpahdmlvhii.supabase.co/functions/v1/submit-lead', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json'
          },
          body: JSON.stringify(quoteForm.value)
        });
        const result = await response.json();
        if (result.success) {
          showNotification('Thank you! We\'ll be in touch soon.', 'success');
          quoteForm.value = {
            full_name: '',
            email: '',
            phone: '',
            company: '',
            notes: ''
          };
        } else {
          showNotification('Something went wrong. Please try again.', 'error');
        }
      } catch (error) {
        showNotification('Network error. Please try again.', 'error');
      } finally {
        isSubmitting.value = false;
      }
    };
    const showNotification = (message, type) => {
      const notification = document.createElement('div');
      notification.className = `notification notification-${type}`;
      notification.innerHTML = `
    <div class="notification-content">
      <i class="fas ${type === 'success' ? 'fa-check-circle' : 'fa-exclamation-circle'}"></i>
      <span>${message}</span>
    </div>
  `;
      document.body.appendChild(notification);
      setTimeout(() => notification.classList.add('show'), 10);
      setTimeout(() => {
        notification.classList.remove('show');
        setTimeout(() => notification.remove(), 300);
      }, 4000);
    };
    const selectPlan = plan => {
      alert(`🎉 You selected the ${plan} Plan for Logo Design!\nOur team will contact you shortly.`);
    };
    const scrollToTop = () => {
      window.scrollTo({
        top: 0,
        behavior: 'smooth'
      });
    };

    // Scroll Top Button Visibility
    onMounted(() => {
      window.addEventListener('scroll', () => {
        showScrollTop.value = window.scrollY > 500;
      });
      console.log('%c✅ Logo Design Page - Vue 3 Loaded Successfully!', 'color:#a855f7; font-size:16px; font-weight:600');
    });
    const __returned__ = {
      quoteForm,
      openFaqIndex,
      showScrollTop,
      isSubmitting,
      faqs,
      toggleFAQ,
      handleQuoteSubmit,
      showNotification,
      selectPlan,
      scrollToTop,
      ref,
      onMounted,
      NavbarSection,
      FooterSection
    };
    Object.defineProperty(__returned__, '__isScriptSetup', {
      enumerable: false,
      value: true
    });
    return __returned__;
  }
};
